#include <stdio.h>
int main() {
    int n, q;
    scanf("%d", &n);
    int h[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &h[i]);
    }
    scanf("%d", &q);
    while (q--) {
        int x, y;
        scanf("%d %d", &x, &y);
        for (int i = 0; i < n; i++) {
            if ((i & x) == i) {
                h[i] -= y;
            }
        }
        int count = 0;
        for (int i = 0; i < n; i++) {
            if (h[i] > 0) {
                count++;
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

