import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();
        int[] h = new int[n];
        for (int i = 0; i < n; i++) {
            h[i] = sc.nextInt();
        }
        int q = sc.nextInt();
        while (q-- > 0) {
            int x = sc.nextInt();
            int y = sc.nextInt();
            for (int i = 0; i < n; i++) {
                if ((i & x) == i) {
                    h[i] -= y;
                }
            }
            int count = 0;
            for (int i = 0; i < n; i++) {
                if (h[i] > 0) {
                    count++;
                }
            }
            System.out.println(count);
        }
    }
}

